import React, { useState, useEffect } from 'react';

const Home = () => {
  const [equipos, setEquipos] = useState([]);
  const [busqueda, setBusqueda] = useState("");

  useEffect(() => {
    fetch("https://site.api.espn.com/apis/site/v2/sports/basketball/nba/teams")
      .then(res => res.json())
      .then(data => {
        setEquipos(data.sports[0].leagues[0].teams);
      })
      .catch(err => console.error("Error cargando NBA:", err));
  }, []);

  // Filtro de búsqueda
  const equiposFiltrados = equipos.filter(item => 
    item.team.displayName.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="main-content">
      <h1 style={{ textAlign: 'center', marginBottom: '30px', color: '#1d428a' }}>
        Temporada Regular NBA
      </h1>

      {/* Buscador */}
      <div className="search-container">
        <input 
          type="text" 
          className="search-input"
          placeholder="Buscar equipo (Lakers, Warriors, Bulls...)" 
          value={busqueda}
          onChange={(e) => setBusqueda(e.target.value)}
        />
      </div>

      {/* Grid de Equipos */}
      <div className="teams-grid">
        {equiposFiltrados.map((t) => (
          <div key={t.team.id} className="team-card">
            <div>
              <img 
                src={t.team.logos[0].href} 
                alt={t.team.name} 
                className="team-logo" 
              />
              <h2 style={{ fontSize: '1.2rem', margin: '10px 0' }}>{t.team.displayName}</h2>
              <p style={{ color: '#666', fontSize: '0.9rem' }}>
                {t.team.location} | <strong>{t.team.abbreviation}</strong>
              </p>
            </div>

            {/* Contenedor del Botón Centrado */}
            <div className="btn-container">
              <button 
                className="btn-main"
                style={{ backgroundColor: `#${t.team.color || '1d428a'}` }}
              >
                VER PLANTILLA
              </button>
              <button className="btn-fav">⭐</button>
            </div>
          </div>
        ))}
      </div>

      {equiposFiltrados.length === 0 && (
        <p style={{ textAlign: 'center', marginTop: '20px' }}>No se encontraron equipos.</p>
      )}
    </div>
  );
};

export default Home;
